sql:
SELECT setting_name, color_temperature 
FROM white_balance_settings 
WHERE setting_id = 1;

SELECT comment
FROM configuration_comments
WHERE config_id = 1;

external_knowledge:
- 'somewhat older sensors' refers to sensors released before '2010-01-01';
- 'standard bit depth' refers to bit depths of 8-bit or higher;
- 'general performance' is calculated as the average of the performance metric values.

sql:
SELECT user_id
FROM user_config_access
WHERE access_level = 'read-write';

SELECT DISTINCT users.*
FROM users
JOIN configuration_comments ON users.user_id = configuration_comments.user_id;
